// Normaliza payload independentemente de onde o body veio
const b = $input.item.json.body ?? $input.item.json;
return [{ json: {
  campanha_id:         b.campanha_id,
  viagem_id:           b.viagem_id ?? null,
  segmento:            b.segmento,
  mensagem:            b.mensagem,
  delay_segundos:      Number(b.delay_segundos ?? 3),
  limite:              Number(b.limite_por_execucao ?? 50),
} }];

// ─────────────────────────────────────────────────────────
// Busca contatos elegíveis no Supabase conforme o segmento
// Variáveis de ambiente necessárias no n8n:
//   SUPABASE_URL           — Project URL
//   SUPABASE_SERVICE_ROLE  — Service Role Key (acesso admin)
// ─────────────────────────────────────────────────────────

const { campanha_id, viagem_id, segmento, mensagem, delay_segundos, limite } = $input.item.json;

const BASE      = $env.SUPABASE_URL + '/rest/v1';
const KEY       = $env.SUPABASE_SERVICE_ROLE;
const HEADERS   = { 'apikey': KEY, 'Authorization': `Bearer ${KEY}` };

async function get(url) {
  const r = await fetch(url, { headers: HEADERS });
  if (!r.ok) throw new Error(`Supabase error ${r.status}: ${await r.text()}`);
  return r.json();
}

// ── Buscar viagem ──────────────────────────────────────────
let viagem = { titulo: '', destino: '', data_saida: '', valor: '', link_publico: '' };
if (viagem_id) {
  const rows = await get(`${BASE}/viagens?id=eq.${viagem_id}&select=titulo,destino,data_saida,valor,link_publico&limit=1`);
  if (rows[0]) viagem = rows[0];
}

// ── Query por segmento ─────────────────────────────────────
const OPT_FILTER = 'opt_out=eq.false&aceitou_receber_mensagens=eq.true';
const LIMIT_QS   = `limit=${limite}`;
let rawRows = [];

switch (segmento) {
  case 'lista_vip':
    rawRows = await get(`${BASE}/clientes?${OPT_FILTER}&origem=eq.lista_vip&select=id,nome,whatsapp,cidade&${LIMIT_QS}`);
    break;
  case 'todos_clientes':
    rawRows = await get(`${BASE}/clientes?${OPT_FILTER}&select=id,nome,whatsapp,cidade&${LIMIT_QS}`);
    break;
  case 'leads_novos':
    rawRows = await get(`${BASE}/interesses?status=eq.novo&select=clientes!inner(id,nome,whatsapp,cidade)&clientes.opt_out=eq.false&${LIMIT_QS}`);
    rawRows = rawRows.map(r => r.clientes).filter(Boolean);
    break;
  case 'leads_nao_convertidos':
    rawRows = await get(`${BASE}/interesses?status=in.(novo,contatado,negociando)&select=clientes!inner(id,nome,whatsapp,cidade)&clientes.opt_out=eq.false&${LIMIT_QS}`);
    rawRows = rawRows.map(r => r.clientes).filter(Boolean);
    break;
  case 'viagem_especifica':
    if (!viagem_id) { rawRows = []; break; }
    rawRows = await get(`${BASE}/interesses?viagem_id=eq.${viagem_id}&select=clientes!inner(id,nome,whatsapp,cidade)&clientes.opt_out=eq.false&${LIMIT_QS}`);
    rawRows = rawRows.map(r => r.clientes).filter(Boolean);
    break;
  default:
    if (segmento.startsWith('categoria_')) {
      const cat = segmento.replace('categoria_', '');
      rawRows = await get(`${BASE}/interesses?categoria=eq.${cat}&select=clientes!inner(id,nome,whatsapp,cidade)&clientes.opt_out=eq.false&${LIMIT_QS}`);
      rawRows = rawRows.map(r => r.clientes).filter(Boolean);
    }
}

// ── Formatar data de saída ─────────────────────────────────
const fmtData = (d) => {
  if (!d) return '';
  const [year, month, day] = d.split('-');
  const meses = ['jan','fev','mar','abr','mai','jun','jul','ago','set','out','nov','dez'];
  return `${parseInt(day)} de ${meses[parseInt(month)-1]} de ${year}`;
};

// ── Normalizar e deduplicar ────────────────────────────────
const seen = new Set();
const contatos = rawRows
  .map(c => ({
    cliente_id:         c.id,
    nome:               c.nome,
    whatsapp:           (c.whatsapp || '').replace(/\D/g, ''),
    cidade:             c.cidade ?? '',
    campanha_id,
    mensagem_template:  mensagem,
    delay_segundos,
    viagem_titulo:      viagem.titulo,
    viagem_destino:     viagem.destino,
    viagem_data_fmt:    fmtData(viagem.data_saida),
    viagem_valor:       viagem.valor ? `R$ ${Number(viagem.valor).toLocaleString('pt-BR', {minimumFractionDigits:2})}` : '',
    viagem_link:        viagem.link_publico ?? '',
  }))
  .filter(c => c.whatsapp.length >= 10)
  .filter(c => { if (seen.has(c.whatsapp)) return false; seen.add(c.whatsapp); return true; });

if (contatos.length === 0) {
  return [{ json: { _sem_contatos: true, campanha_id } }];
}

return contatos.map(c => ({ json: c }));

// Personaliza a mensagem substituindo variáveis {{...}}
const j = $input.item.json;
const msg = j.mensagem_template
  .replace(/\{\{nome\}\}/g,       j.nome        || 'amigo(a)')
  .replace(/\{\{destino\}\}/g,    j.viagem_destino  || '')
  .replace(/\{\{data_saida\}\}/g, j.viagem_data_fmt  || '')
  .replace(/\{\{valor\}\}/g,      j.viagem_valor     || '')
  .replace(/\{\{link_viagem\}\}/g, j.viagem_link     || '');
return [{ json: { ...j, mensagem_final: msg } }];

// Salva o resultado do envio no Supabase
const j     = $input.item.json;
const BASE  = $env.SUPABASE_URL + '/rest/v1';
const KEY   = $env.SUPABASE_SERVICE_ROLE;

const ok     = !j.error && j.key !== undefined;
const status = ok ? 'enviado' : 'erro';

await fetch(`${BASE}/mensagens_whatsapp`, {
  method: 'POST',
  headers: {
    'apikey': KEY,
    'Authorization': `Bearer ${KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal',
  },
  body: JSON.stringify({
    campanha_id:  j.campanha_id,
    cliente_id:   j.cliente_id ?? null,
    whatsapp:     j.whatsapp,
    mensagem:     j.mensagem_final,
    status_envio: status,
    resposta_api: ok ? j : null,
    enviado_em:   ok ? new Date().toISOString() : null,
    erro:         ok ? null : (j.message || JSON.stringify(j)),
  }),
});

return [{ json: { ...j, _status_envio: status } }];

// Atualiza o total_enviados na campanha
const campanha_id = $input.item.json.campanha_id;
const BASE = $env.SUPABASE_URL + '/rest/v1';
const KEY  = $env.SUPABASE_SERVICE_ROLE;

// Contar enviados
const r = await fetch(
  `${BASE}/mensagens_whatsapp?campanha_id=eq.${campanha_id}&status_envio=eq.enviado&select=id`,
  { headers: { 'apikey': KEY, 'Authorization': `Bearer ${KEY}`, 'Prefer': 'count=exact' } }
);
const total = parseInt(r.headers.get('Content-Range')?.split('/')[1] ?? '0');

// Atualizar campanha
await fetch(
  `${BASE}/campanhas_whatsapp?id=eq.${campanha_id}`,
  {
    method: 'PATCH',
    headers: {
      'apikey': KEY,
      'Authorization': `Bearer ${KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal',
    },
    body: JSON.stringify({ total_enviados: total }),
  }
);

return [{ json: { campanha_id, total_enviados: total } }];
